#include <bits/stdc++.h>
using namespace std;
struct node
{
    int u,d;
};
vector<node> v[105];
vector<int> v2;
int c[105],b[105][105],n,k,m,s,t,vis[105],ans=-1;
bool check(int x)
{
    for(int i=0;i<v2.size();i++)
    {
        if(b[x][v2[i]]==1) return false;
    }
    return true;
}
void dfs(int x,int step)
{
    v2.push_back(c[x]);
    if(ans<=step&&ans!=-1) return ;
    if(x==t)
    {
        if(ans!=-1) ans=min(ans,step);
        else ans=step;
        return ;
    }
    vis[x]=1;
    for(int i=0;i<v[x].size();i++)
    {
        node t=v[x][i];
        if(check(c[t.u])&&vis[t.u]==0) dfs(t.u,step+t.d);
    }
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>n>>k>>m>>s>>t;
    for(int i=1;i<=n;i++) cin>>c[i];
    for(int i=1;i<=k;i++)
    {
        for(int j=1;j<=k;j++) cin>>b[i][j];
    }
    for(int i=1;i<=m;i++)
    {
        int u1,v1,d;
        cin>>u1>>v1>>d;
        node t;
        t.d=d;
        t.u=v1;
        v[u1].push_back(t);
        t.u=u1;
        v[v1].push_back(t);
    }
    dfs(s,0);
    cout<<ans;
    return 0;
}
